import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)


const state = {
    snackbar: {
        isOpen: false,
        timeout: 1000,
        text: "Copied!"
    },
    scrollTop: 0
}

const getters = {};

const actions = {};

const mutations = {
    setSnackbarStatus(state, status) {
        state.snackbar.isOpen = status;
    },
    setSnackbarText(state, text) {
        state.snackbar.text = text;
    },
    updateScrollTop(state, value) {
        state.scrollTop = value;
    }
};


export default new Vuex.Store({
    state,
    getters,
    actions,
    mutations
})