<template>
  <div class="Home">
    <!------------------------->
    <!---- WELCOME MESSAGE ---->
    <!------------------------->
    <v-row class="welcomeMessage fillPage">
      <v-col>
        <v-row align="center" justify="center">
          <v-col>
            <vue-typer
              class="text-h1 helloString"
              :text="helloString"
              :repeat="0"
              @typed="helloStringFinished = true"
            />
            <br />
            <vue-typer
              class="pl-md-2 pl-1 text-h4 font-weight-light"
              :text="whoAmIString"
              :repeat="0"
              :pre-type-delay="helloString.length * 70 + 200"
              :style="{visibility: helloStringFinished ? 'visible' : 'hidden'}"
            />
          </v-col>
        </v-row>

        <v-row>
          <v-col>
            <transition name="fade">
              <a
                class="caption scrollDownInfo"
                @click="goTo('about')"
                v-show="isScrollDownInfoVisible"
              >
                Scroll down for more
                <v-icon>mdi-chevron-down</v-icon>
              </a>
            </transition>
          </v-col>
        </v-row>
      </v-col>
    </v-row>

    <!------------------------->
    <!--------- ABOUT --------->
    <!------------------------->
    <v-row justify="center" class="fillPage aboutSection">
      <v-col>
        <v-row>
          <v-col align-self="start" cols="12" class="titleCol">
            <h1 ref="about" class="text-h1 ml-xl-16 ml-lg-14 ml-sm-10 ml-3" id="about">About me</h1>
          </v-col>
        </v-row>
        <v-row>
          <v-col cols="1" sm="3" md="5">
            <v-spacer></v-spacer>
          </v-col>
          <v-col cols="10" sm="8" md="6" class="text-justify ml-5 ml-md-5">
            <p class="text-h5">{{ aboutMe }}</p>
            <p class="text-h6 pt-4" style="opacity: 0.8">
              If you'd like to say hi, you can send an email to:
              <span
                class="text-right text-sm-justify d-block d-sm-inline"
              >{{ "simonecarletti.work\u200B@gmail.com" }}</span>
            </p>
          </v-col>
        </v-row>
      </v-col>
    </v-row>
  </div>
</template>

<script>
import { VueTyper } from "vue-typer";

export default {
  name: "Home",
  components: { VueTyper },
  data() {
    return {
      helloStringFinished: false,
      aboutMe: `Hi! I'm an IT student & developer from Italy, currently mostly focused on web-dev. 
        When I'm not at the computer I love to shoot photographs and play the guitar.
        You can check out my work using the links at the top!`,
      isScrollDownInfoVisible: true
    };
  },
  methods: {
    goTo(refName) {
      let element = this.$refs[refName];
      element.scrollIntoView();
    }
  },
  computed: {
    scrollTop() {
      return this.$store.state.scrollTop;
    },
    helloString() {
      return this.$vuetify.breakpoint.xsOnly
        ? "Hi, I'm\nSimone."
        : "Hi, I'm Simone.";
    },
    whoAmIString() {
      return this.$vuetify.breakpoint.xsOnly
        ? "Developer, Student\n& Photographer"
        : "Developer, Student & Photographer";
    }
  },
  watch: {
    scrollTop(val) {
      // hide scroll down info when already scrolled 15% of window height
      val > 0.15 * window.innerHeight
        ? (this.isScrollDownInfoVisible = false)
        : (this.isScrollDownInfoVisible = true);
    }
  }
};
</script>

<style scoped>
.vue-typer,
.Home * {
  font-family: "ARegular" !important;
}

@media (max-width: 358px) {
  .helloString {
    font-size: 5rem !important;
    line-height: 5rem !important;
  }
}

@media (min-width: 960px) {
  .text-h1 {
    font-size: 9rem !important;
    line-height: 9rem !important;
  }
}

@media (min-width: 1264px) {
  .text-h1 {
    font-size: 11rem !important;
    line-height: 11rem !important;
  }
}

.text-h4 {
  font-size: 1.8rem !important;
  line-height: 1.8rem !important;
}

.fillPage {
  position: relative;
  height: 100vh; /* Use vh as a fallback for browsers that do not support Custom Properties */
  height: calc(var(--vh, 1vh) * 100);
  width: 100vw;
}

.aboutSection .text-h1 {
  font-family: "AMedium" !important;
}

.aboutSection .titleCol {
  margin-top: 9vh;
}

/* mobile */
@media (max-width: 600px) {
  .aboutSection {
    height: 100%;
  }

  .aboutSection .titleCol {
    margin-top: inherit;
  }
}

.welcomeMessage {
  padding-bottom: 10em;
  align-content: center;
  display: flex;
}

.scrollDownInfo {
  font-family: "ALight" !important;
  position: absolute;
  right: 0.5rem;
  bottom: 5rem;
  font-size: 0.9rem !important;
}

.scrollDownInfo .v-icon {
  font-size: 1.3rem !important;
}

/* Desktops */
@media (min-width: 601px) {
  .scrollDownInfo {
    right: 2.1rem;
    right: 1.3rem;
    margin-bottom: 1rem;
    font-size: 1.2rem !important;
  }

  .scrollDownInfo .v-icon {
    font-size: 1.4rem !important;
  }
}

.scrollArrow svg {
  height: 2.1rem;
}

.scrollArrow polygon {
  fill: #3b3a3a;
}

.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.3s;
}
.fade-enter,
.fade-leave-to {
  opacity: 0;
}
</style>
